<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>Conway's Game of Life</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;height:100vh}
  #controls{padding:10px;text-align:center}
  button{margin:5px;padding:8px 12px;border:none;background:#444;color:#eee;border-radius:4px;cursor:pointer}
  button:hover{background:#555}
  canvas#life{display:block;margin:auto;background:#111;border:1px solid #333}
</style>
</head>
<body>
<div id="controls">
  <button id="step">Step</button>
  <button id="play">Play</button>
  <button id="random">Random</button>
  <button id="clear">Clear</button>
</div>
<canvas id="life" width="400" height="400"></canvas>

<script>
(() => {
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const w = 40, h = 40; // grid size
  const cellSize = canvas.width / w;
  let grid = new Uint8Array(w*h);
  let running = false, animFrame;

  function idx(x,y){return y*w+x}
  function get(x,y){ return (x<0||y<0||x>=w||y>=h)?0:grid[idx(x,y)] }
  function set(x,y,v){ if(x>=0&&y>=0&&x<w&&y<h) grid[idx(x,y)] = v?1:0 }

  function draw(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        if(grid[idx(x,y)]){ctx.fillStyle='#0f0';}
        else{ctx.fillStyle='#111';}
        ctx.fillRect(x*cellSize,y*cellSize,cellSize-1,cellSize-1);
      }
    }
  }

  function step(){
    const next = new Uint8Array(w*h);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        let liveNeighbors =
          get(x-1,y-1)+get(x,y-1)+get(x+1,y-1)+
          get(x-1,y  )            +get(x+1,y  )+
          get(x-1,y+1)+get(x,y+1)+get(x+1,y+1);
        const cur = get(x,y);
        if(cur){
          next[idx(x,y)] = (liveNeighbors===2||liveNeighbors===3)?1:0;
        }else{
          next[idx(x,y)] = (liveNeighbors===3)?1:0;
        }
      }
    }
    grid = next;
    draw();
  }

  function clear(){grid.fill(0);draw();}
  function random(){
    for(let i=0;i<grid.length;i++) grid[i] = Math.random()<0.2?1:0;
    draw();
  }

  // API
  window.life = {w,h,get,set,step,clear};

  document.getElementById('step').onclick = step;
  document.getElementById('clear').onclick = clear;
  document.getElementById('random').onclick = random;

  const playBtn=document.getElementById('play');
  playBtn.onclick=function(){
    running=!running;
    if(running){playBtn.textContent='Pause';stepLoop();}
    else{playBtn.textContent='Play';cancelAnimationFrame(animFrame);}
  };
  function stepLoop(){step();animFrame=requestAnimationFrame(stepLoop);}

  // Mouse interaction
  let drawing=false, lastState=0;
  canvas.addEventListener('mousedown',e=>{
    drawing=true; toggleCell(e);
    lastState=get(cellX(e),cellY(e));
  });
  canvas.addEventListener('mousemove',e=>{
    if(drawing){toggleCell(e);}
  });
  window.addEventListener('mouseup',()=>drawing=false);

  function cellX(e){return Math.floor((e.offsetX)/cellSize);}
  function cellY(e){return Math.floor((e.offsetY)/cellSize);}

  function toggleCell(e){
    const x=cellX(e),y=cellY(e);
    if(x<0||y<0||x>=w||y>=h)return;
    set(x,y,1-get(x,y));
    draw();
  }

  // Initial draw
  draw();
})();
</script>
</body>
</html>
